CREATE TYPE public.report_target_type AS ENUM ('message','transcript_entry','debate','live_session','change_my_mind','profile','club','club_event','notebook','my_take','comment'); CREATE TYPE public.report_reason AS ENUM ('spam','harassment','hate','sexual','violence','misinformation','self_harm','other'); CREATE TYPE public.report_status AS ENUM ('open','triaged','actioned','dismissed'); CREATE TYPE public.sanction_kind AS ENUM ('warning','mute_24h','mute_7d','suspend','ban'); CREATE TABLE public.content_reports (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), reporter_id uuid NOT NULL, target_type public.report_target_type NOT NULL, target_id uuid NOT NULL, reason public.report_reason NOT NULL, details text, status public.report_status NOT NULL DEFAULT 'open', severity smallint NOT NULL DEFAULT 1 CHECK (severity BETWEEN 1 AND 5), reviewer_id uuid, reviewed_at timestamptz, resolution_note text, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX idx_content_reports_status ON public.content_reports(status, created_at DESC); CREATE INDEX idx_content_reports_target ON public.content_reports(target_type, target_id); CREATE INDEX idx_content_reports_reporter ON public.content_reports(reporter_id, created_at DESC); ALTER TABLE public.content_reports ENABLE ROW LEVEL SECURITY; CREATE OR REPLACE FUNCTION public.enforce_report_rate_limit() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $func$ DECLARE c int; BEGIN SELECT count(*) INTO c FROM public.content_reports WHERE reporter_id = NEW.reporter_id AND created_at > now() - interval '24 hours'; IF c >= 20 THEN RAISE EXCEPTION 'Report rate limit reached (20 per 24h)'; END IF; RETURN NEW; END; $func$; CREATE TRIGGER trg_content_reports_rate BEFORE INSERT ON public.content_reports FOR EACH ROW EXECUTE FUNCTION public.enforce_report_rate_limit(); CREATE TRIGGER trg_content_reports_updated BEFORE UPDATE ON public.content_reports FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column(); CREATE POLICY "Anyone signed-in can file a report" ON public.content_reports FOR INSERT TO authenticated WITH CHECK (auth.uid() = reporter_id); CREATE POLICY "Reporters see only their reports" ON public.content_reports FOR SELECT TO authenticated USING (auth.uid() = reporter_id OR public.is_admin(auth.uid())); CREATE POLICY "Admins can update reports" ON public.content_reports FOR UPDATE TO authenticated USING (public.is_admin(auth.uid())) WITH CHECK (public.is_admin(auth.uid())); CREATE POLICY "Admins can delete reports" ON public.content_reports FOR DELETE TO authenticated USING (public.is_admin(auth.uid())); CREATE TABLE public.content_sanctions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL, kind public.sanction_kind NOT NULL, reason text, related_report_id uuid REFERENCES public.content_reports(id) ON DELETE SET NULL, issued_by uuid NOT NULL, expires_at timestamptz, appealed_at timestamptz, appeal_note text, appeal_status text CHECK (appeal_status IN ('pending','accepted','denied')), revoked_at timestamptz, created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX idx_content_sanctions_user ON public.content_sanctions(user_id, created_at DESC); ALTER TABLE public.content_sanctions ENABLE ROW LEVEL SECURITY; CREATE POLICY "Users can view their own sanctions" ON public.content_sanctions FOR SELECT TO authenticated USING (auth.uid() = user_id OR public.is_admin(auth.uid())); CREATE POLICY "Admins manage sanctions" ON public.content_sanctions FOR ALL TO authenticated USING (public.is_admin(auth.uid())) WITH CHECK (public.is_admin(auth.uid())); CREATE OR REPLACE FUNCTION public.is_user_silenced(_user_id uuid) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path = public AS $func$ SELECT EXISTS (SELECT 1 FROM public.content_sanctions WHERE user_id = _user_id AND revoked_at IS NULL AND kind IN ('mute_24h','mute_7d','suspend','ban') AND (expires_at IS NULL OR expires_at > now())); $func$;